data.content:
MSTest **does not** have `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you actually use:

| Need | MSTest Assertion |
|---|---|
| Exact value | `Assert.AreEqual(expected, actual)` |
| Double tolerance | `Assert.AreEqual(expected, actual, delta)` |
| Comparisons (>, <, etc.) | `Assert.IsTrue(actual > value)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

The `delta` overload on `AreEqual` is key for floating-point boundaries. For range checks, `Assert.IsTrue()` is the idiomatic MSTest approach.

Here's a complete test class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333)]
    public void CalculatePercentage_ReturnsExpected(int correct, int total, double expected)
    {
        double result = _calc.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result, 0.001);  // delta handles floating-point
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(3, 7);
        Assert.IsTrue(result >= 0.0, $"Expected >= 0 but was {result}");
        Assert.IsTrue(result <= 100.0, $"Expected <= 100 but was {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade ─────────────────────────────────────────

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]   // just below A boundary
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    [DataRow(100.0, "A")]
    public void GetGrade_BoundaryValues(double percentage, string expectedGrade)
    {
        Assert.AreEqual(expectedGrade, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ───────────────────────────────────

    [TestMethod]
    public void NormalizeScore_StandardCase()
    {
        double result = _calc.NormalizeScore(40, 50);
        Assert.AreEqual(80.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, 0.001);
        Assert.IsTrue(result <= 100.0);  // verify the cap
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 50));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(10, 0));
    }
}
```

**Key patterns used:**
- **`Assert.AreEqual(expected, actual, 0.001)`** — the `delta` overload is the correct way to compare doubles with tolerance
- **`Assert.IsTrue(result >= 0.0, "message")`** — always add a message string for comparison checks, since bare `IsTrue` failures just say "expected true, was false"
- **`Assert.ThrowsException<T>`** — for boundary validation exceptions
- **`[DataRow]`** — to test grade boundaries (89.999 vs 90.0) without duplicating test methods
